import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges) {
        // Build adjacency list
        List<List<pair<Long, Long>>> adj = new ArrayList<>();
        for (long i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }
        for (long[] edge : edges) {
            long u = edge[0], v = edge[1], w = edge[2];
            adj.get(u).add(new pair<>(v, w));
        }

        // Dijkstra's algorithm with state (node, switch_used)
        // switch_used is a boolean indicating whether the switch at the node has been used
        PriorityQueue<pair<Long, pair<Long, Boolean>>> pq = new PriorityQueue<>((a, b) -> {
            return a.first.compareTo(b.first);
        });
        long[][] dist = new long[n][2];
        for (long i = 0; i < n; i++) {
            Arrays.fill(dist[i], Long.MAX_VALUE);
        }
        dist[0][0] = 0;
        pq.offer(new pair<>(0, new pair<>(0, false)));

        while (!pq.isEmpty()) {
            long cost = pq.peek().first;
            long u = pq.peek().second.first;
            boolean switch_used = pq.peek().second.second;
            pq.poll();

            if (u == n - 1) {
                return cost;
            }

            if (cost > dist[u][switch_used]) {
                continue;
            }

            // Traverse normal edges
            for (pair<Long, Long> edge : adj.get(u)) {
                long v = edge.first, w = edge.second;
                long new_cost = cost + w;
                if (new_cost < dist[v][switch_used]) {
                    dist[v][switch_used] = new_cost;
                    pq.offer(new pair<>(new_cost, new pair<>(v, switch_used)));
                }
            }

            // If switch is not used, consider reversing the edge
            if (!switch_used) {
                // Reverse the edge (original edge is from u to v, now it's v to u)
                long new_cost_rev = cost + 2 * (long) adj.get(u).get(0).second;
                if (new_cost_rev < dist[u][true]) {
                    dist[u][true] = new_cost_rev;
                    pq.offer(new pair<>(new_cost_rev, new pair<>(u, true)));
                }
            }
        }

        return -1;
    }

    static class pair<T1, T2> {
        T1 first;
        T2 second;

        pair(T1 f, T2 s) {
            this.first = f;
            this.second = s;
        }
    }
}
